import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

export default function AddTransaction() {
  const [form, setForm] = useState({
    name: "",
    amount: "",
    interestRate: "",
    interestType: "Simple",
    dueDate: "",
    givenOrTaken: "Given",
  });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    try {
      const token = localStorage.getItem("token");
      const response = await fetch(
        "http://localhost:5000/api/transactions/add",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify(form),
        }
      );
      const data = await response.json();
      if (response.ok) {
        navigate("/homepage");
      } else {
        setError(data.message || "Failed to add transaction");
      }
    } catch {
      setError("Failed to add transaction");
    }
  };

  const inputStyle = {
    width: "100%",
    padding: "12px 15px",
    border: "1px solid #ccc",
    borderRadius: 6,
    fontSize: 16,
  };

  return (
    <div
      style={{
        maxWidth: 500,
        margin: "40px auto",
        padding: 30,
        background: "#f9f9f9",
        borderRadius: 12,
        boxShadow: "0 4px 20px rgba(0,0,0,0.05)",
        display: "flex",
        flexDirection: "column",
        gap: 20,
      }}
    >
      <h1
        style={{
          fontWeight: "bold",
          fontSize: 24,
          textAlign: "center",
          marginBottom: 20,
        }}
      >
        Add Transaction
      </h1>
      <form
        onSubmit={handleSubmit}
        style={{ display: "flex", flexDirection: "column", gap: 20 }}
      >
        <input
          type="text"
          name="name"
          placeholder="Name"
          value={form.name}
          onChange={handleChange}
          style={inputStyle}
          required
        />
        <input
          type="number"
          name="amount"
          placeholder="Amount"
          value={form.amount}
          onChange={handleChange}
          style={inputStyle}
          min="0"
          step="0.01"
          required
        />
        <input
          type="number"
          name="interestRate"
          placeholder="Interest Rate (%)"
          value={form.interestRate}
          onChange={handleChange}
          style={inputStyle}
          min="0"
          max="100"
          step="0.01"
          required
        />
        <select
          name="interestType"
          value={form.interestType}
          onChange={handleChange}
          style={inputStyle}
        >
          <option value="Simple">Simple</option>
          <option value="Compound">Compound</option>
        </select>
        <input
          type="date"
          name="dueDate"
          value={form.dueDate}
          onChange={handleChange}
          style={inputStyle}
          required
        />
        <select
          name="givenOrTaken"
          value={form.givenOrTaken}
          onChange={handleChange}
          style={inputStyle}
        >
          <option value="Given">Given</option>
          <option value="Taken">Taken</option>
        </select>
        {error && (
          <div style={{ color: "red", fontWeight: "600", textAlign: "center" }}>
            {error}
          </div>
        )}
        <button
          type="submit"
          style={{
            width: "100%",
            padding: "14px 0",
            backgroundColor: "#5D5FEF",
            color: "white",
            border: "none",
            borderRadius: 8,
            fontWeight: 600,
            fontSize: 18,
            cursor: "pointer",
            transition: "background-color 0.3s ease",
          }}
          onMouseOver={(e) =>
            (e.currentTarget.style.backgroundColor = "#4a4eda")
          }
          onMouseOut={(e) =>
            (e.currentTarget.style.backgroundColor = "#5D5FEF")
          }
        >
          Add Transaction
        </button>
      </form>
    </div>
  );
}
